external_knowledge:
- "blossoming flowers" metaphorically refers to products that are currently active and successful;
- "withered" symbolizes discontinued or inactive products;
- "thriving product lines" indicates those that are marked as active in the database.

sql:
SELECT COUNT(*) AS active_product_lines
FROM product_lines
WHERE is_active = 1;

SELECT COUNT(*) AS total_active_product_lines
FROM product_lines
WHERE brand_id = 1 AND is_active = 1;

SELECT product_line_name
FROM product_lines
WHERE is_active = 1;

SELECT p.product_name, pl.product_line_name
FROM products p
INNER JOIN product_lines pl ON p.product_line_id = pl.product_line_id;
